const order = items[0].json;

// Map failure reason (right now you have no gateway message)
let failure_reason_raw = order.payment_method_title || "Unknown";
let failure_reason_canonical = "unknown";

// Canonical reason mapper (expand later)
if (failure_reason_raw.toLowerCase().includes("expire")) {
  failure_reason_canonical = "card_expired";
} else if (failure_reason_raw.toLowerCase().includes("declin")) {
  failure_reason_canonical = "card_declined";
}

return [{
  order_id: order.id,
  invoice_amount: order.total,
  currency: order.currency,
  customer_name: `${order.billing.first_name} ${order.billing.last_name}`,
  customer_email: order.billing.email,
  payment_method: order.payment_method,
  failure_reason_raw,
  failure_reason_canonical,
  attempts_count: 1,

  order_items_summary: order.line_items?.length
    ? order.line_items.map(i => `${i.name} x ${i.quantity}`).join(", ")
    : "No items found",

  links: {
    order_admin_url: `https://{{YOUR_DOMAIN}}/wp-admin/post.php?post=${order.id}&action=edit`,
    customer_profile_url: "",
    retry_payment_url: order.payment_url
  }
}];

